mapper.select:
SELECT MODL_CD, MAX(MODL_NM) MODL_NM, SUM(M1) stb_qty1, SUM(M1_M2) stb_qty2, SUM(M2_M3) stb_qty3, SUM(M3_M4) stb_qty4, SUM(M4_M5) stb_qty5, SUM(M5_M6) stb_qty6, SUM(M6_M7) stb_qty7, SUM(M7_M8) stb_qty8, SUM(M8_M9) stb_qty9, SUM(M9_M10) stb_qty10, SUM(M10_M11) stb_qty11, SUM(M11_M12) stb_qty12, SUM(Y1) stb_qty13, SUM(N) stb_qty14 FROM( SELECT DDM.STB_ID AS STB_ID ,PS.MAC_ADDRESS AS STB_MAC ,PS.MODEL_CODE AS MODL_CD ,NVL(SM.MODEL_NAME,'정보없음') AS MODL_NM ,DDM.STM_UPTM ,(CASE WHEN DDM.STM_UPTM > TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '1' MONTH) +0.99999 THEN 1 ELSE 0 END) AS M1 ,(CASE WHEN DDM.STM_UPTM BETWEEN TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '2' MONTH) AND TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '1' MONTH) +0.99999 THEN 1 ELSE 0 END) M1_M2 ,(CASE WHEN DDM.STM_UPTM BETWEEN TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '3' MONTH) AND TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '2' MONTH) +0.99999 THEN 1 ELSE 0 END) M2_M3 ,(CASE WHEN DDM.STM_UPTM BETWEEN TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '4' MONTH) AND TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '3' MONTH) +0.99999 THEN 1 ELSE 0 END) M3_M4 ,(CASE WHEN DDM.STM_UPTM BETWEEN TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '5' MONTH) AND TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '4' MONTH) +0.99999 THEN 1 ELSE 0 END) M4_M5 ,(CASE WHEN DDM.STM_UPTM BETWEEN TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '6' MONTH) AND TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '5' MONTH) +0.99999 THEN 1 ELSE 0 END) M5_M6 ,(CASE WHEN DDM.STM_UPTM BETWEEN TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '7' MONTH) AND TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '6' MONTH) +0.99999 THEN 1 ELSE 0 END) M6_M7 ,(CASE WHEN DDM.STM_UPTM BETWEEN TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '8' MONTH) AND TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '7' MONTH) +0.99999 THEN 1 ELSE 0 END) M7_M8 ,(CASE WHEN DDM.STM_UPTM BETWEEN TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '9' MONTH) AND TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '8' MONTH) +0.99999 THEN 1 ELSE 0 END) M8_M9 ,(CASE WHEN DDM.STM_UPTM BETWEEN TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '10' MONTH) AND TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '9' MONTH) +0.99999 THEN 1 ELSE 0 END) M9_M10 ,(CASE WHEN DDM.STM_UPTM BETWEEN TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '11' MONTH) AND TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '10' MONTH) +0.99999 THEN 1 ELSE 0 END) M10_M11 ,(CASE WHEN DDM.STM_UPTM BETWEEN TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '12' MONTH) AND TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '11' MONTH) +0.99999 THEN 1 ELSE 0 END) M11_M12 ,(CASE WHEN DDM.STM_UPTM < TO_DATE(TO_CHAR(SYSDATE,'YYYY-MM'), 'YYYY-MM') - (INTERVAL '12' MONTH) THEN 1 ELSE 0 END) Y1 ,(CASE WHEN DDM.STM_UPTM IS NULL THEN 1 ELSE 0 END) N FROM DM_DVC_MST DDM ,STB STB ,PHYSICAL_STB PS ,STB_MODEL SM ,STB_DTL SD WHERE 1=1 AND DDM.STB_ID = STB.STB_ID(+) AND DDM.STB_ID = PS.STB_ID(+) AND PS.MODEL_CODE = SM.MODEL_CODE(+) AND DDM.STB_ID = SD.STB_ID(+)
AND PS.MODEL_CODE IN
#{value}
AND SD.scrbr_typ_cd = #{scrbrTypCd}
) GROUP BY MODL_CD ORDER BY MODL_NM, MODL_CD
